// S1 VPS Guard Ultimate — Deterministic Health Parser v1.0
// NO IA. JavaScript puro. Cada metrica parseada deterministicamente.
const stdout = $input.first().json.stdout || '';
const stderr = $input.first().json.stderr || '';

if (!stdout) {
  return [{ json: {
    ssh_ok: false, severity: 'CRITICAL',
    summary: 'SSH: no output received',
    timestamp: new Date().toISOString(),
    issues: [{ component: 'SSH', severity: 'CRITICAL', detail: stderr || 'Empty SSH output', fix: 'Check VPS connectivity' }],
    metrics: {}
  }}];
}

function getSection(text, name) {
  const marker = '===' + name + '===';
  const start = text.indexOf(marker);
  if (start === -1) return '';
  const contentStart = text.indexOf('\n', start);
  if (contentStart === -1) return '';
  const nextMarker = text.indexOf('\n===', contentStart + 1);
  return nextMarker === -1 ? text.substring(contentStart + 1).trim() : text.substring(contentStart + 1, nextMarker).trim();
}

const issues = [];
const metrics = {};
let maxSeverity = 'HEALTHY';

function addIssue(component, severity, detail, fix) {
  issues.push({ component, severity, detail, fix: fix || 'None' });
  if (severity === 'CRITICAL') maxSeverity = 'CRITICAL';
  else if (severity === 'WARNING' && maxSeverity !== 'CRITICAL') maxSeverity = 'WARNING';
}

// META
const meta = getSection(stdout, 'META');
const metaLines = meta.split('\n');
metrics.check_time = metaLines[0] || new Date().toISOString();
metrics.hostname = metaLines[1] || 'unknown';
metrics.uptime_since = metaLines[2] || 'unknown';

// DOCKER
const docker = getSection(stdout, 'DOCKER');
const containers = docker.split('\n').filter(l => l.includes('|'));
const criticalNames = ['n8n', 'postgresql', 'qdrant', 'coolify-proxy', 'coolify', 'filebrowser', 'vaultwarden'];
let cHealthy = 0;
const containerStatus = {};
containers.forEach(line => {
  const parts = line.split('|');
  const name = parts[0]; const state = parts[1]; const status = parts[2] || '';
  containerStatus[name] = { state, status };
  if (state === 'running') cHealthy++;
  if (criticalNames.some(c => name.includes(c)) && state !== 'running') {
    addIssue('DOCKER', 'CRITICAL', name + ' is ' + state, 'docker restart ' + name);
  }
});
metrics.containers_healthy = cHealthy;
metrics.containers_total = containers.length;
metrics.containers = containerStatus;

// DISK
const disk = getSection(stdout, 'DISK');
disk.split('\n').filter(l => l.startsWith('/')).forEach(line => {
  const parts = line.split(/\s+/);
  const pct = parseInt(parts[4]); const mount = parts[5];
  const key = mount === '/' ? 'disk_root_percent' : 'disk_data_percent';
  metrics[key] = pct;
  if (pct > 90) addIssue('DISK', 'CRITICAL', mount + ' at ' + pct + '%', 'docker system prune -af');
  else if (pct > 80) addIssue('DISK', 'WARNING', mount + ' at ' + pct + '%', 'du -sh /data/* | sort -rh');
});

// RAM
const ram = getSection(stdout, 'RAM');
const memLine = ram.split('\n').find(l => l.startsWith('Mem:'));
if (memLine) {
  const p = memLine.split(/\s+/);
  metrics.ram_total_mb = parseInt(p[1]); metrics.ram_used_mb = parseInt(p[2]); metrics.ram_available_mb = parseInt(p[6]);
  if (metrics.ram_available_mb < 200) addIssue('RAM', 'CRITICAL', metrics.ram_available_mb + 'MB available', 'docker system prune -af');
  else if (metrics.ram_available_mb < 500) addIssue('RAM', 'WARNING', metrics.ram_available_mb + 'MB available', 'free -m');
}

// CPU
const cpu = getSection(stdout, 'CPU');
const cpuLines = cpu.split('\n');
if (cpuLines.length >= 2) {
  const loads = cpuLines[0].split(' ');
  metrics.cpu_load_1m = parseFloat(loads[0]); metrics.cpu_load_5m = parseFloat(loads[1]); metrics.cpu_load_15m = parseFloat(loads[2]);
  metrics.cpu_cores = parseInt(cpuLines[1]);
  if (metrics.cpu_load_1m > metrics.cpu_cores * 1.5) addIssue('CPU', 'CRITICAL', 'Load ' + metrics.cpu_load_1m + ' (cores: ' + metrics.cpu_cores + ')', 'top -b -n 1 | head -20');
  else if (metrics.cpu_load_1m > metrics.cpu_cores) addIssue('CPU', 'WARNING', 'Load ' + metrics.cpu_load_1m, 'top -b -n 1 | head -20');
}

// SWAP
const swap = getSection(stdout, 'SWAP');
const swapMatch = swap.match(/Swap:\s+(\d+)\s+(\d+)/);
if (swapMatch) {
  metrics.swap_total_mb = parseInt(swapMatch[1]); metrics.swap_used_mb = parseInt(swapMatch[2]);
  metrics.swap_percent = metrics.swap_total_mb > 0 ? Math.round(metrics.swap_used_mb / metrics.swap_total_mb * 100) : 0;
  if (metrics.swap_percent > 80) addIssue('SWAP', 'WARNING', 'Swap at ' + metrics.swap_percent + '%', 'free -m');
}

// NETWORK
metrics.listening_ports = parseInt(getSection(stdout, 'NETWORK')) || 0;

// PG
const pg = getSection(stdout, 'PG');
metrics.pg_ready = pg.includes('accepting connections');
if (!metrics.pg_ready) addIssue('POSTGRES', 'CRITICAL', 'PostgreSQL not accepting connections', 'docker restart $(docker ps -qf name=postgresql)');

// QDRANT
const qdrant = getSection(stdout, 'QDRANT');
metrics.qdrant_healthy = qdrant.includes('healthy');
if (!metrics.qdrant_healthy && !qdrant.includes('unknown')) addIssue('QDRANT', 'CRITICAL', 'Qdrant: ' + qdrant, 'docker restart $(docker ps -qf name=qdrant)');
else if (qdrant.includes('unknown')) addIssue('QDRANT', 'WARNING', 'Qdrant status unknown', 'docker ps -a | grep qdrant');

// COOLIFY
const coolify = getSection(stdout, 'COOLIFY');
metrics.coolify_http = parseInt(coolify) || 0;
if (![200, 302].includes(metrics.coolify_http)) addIssue('COOLIFY', 'WARNING', 'HTTP ' + metrics.coolify_http, 'docker restart coolify');

// FAIL2BAN
metrics.fail2ban_banned = parseInt(getSection(stdout, 'FAIL2BAN')) || 0;
if (metrics.fail2ban_banned > 50) addIssue('FAIL2BAN', 'WARNING', metrics.fail2ban_banned + ' IPs banned', 'fail2ban-client status sshd');

// BACKUP
const backup = getSection(stdout, 'BACKUP');
const bParts = backup.split(/\s+/);
metrics.backup_size_bytes = parseInt(bParts[0]) || 0;
metrics.backup_age_hours = parseInt(bParts[1]) || 999;
if (metrics.backup_age_hours > 48) addIssue('BACKUP', 'CRITICAL', 'Last backup ' + metrics.backup_age_hours + 'h ago', 'bash /usr/local/bin/aurenix-backup-pro.sh');
else if (metrics.backup_age_hours > 26) addIssue('BACKUP', 'WARNING', 'Last backup ' + metrics.backup_age_hours + 'h ago', 'crontab -l');
if (metrics.backup_size_bytes > 0 && metrics.backup_size_bytes < 1024) addIssue('BACKUP', 'WARNING', 'Backup too small', 'ls -la /data/agencia/backups/db/');

// N8N
const n8n = getSection(stdout, 'N8N');
metrics.n8n_healthy = n8n.includes('ok');
if (!metrics.n8n_healthy) addIssue('N8N', 'CRITICAL', 'n8n healthz failed', 'docker restart $(docker ps -qf name=n8n)');

// SSL
const ssl = getSection(stdout, 'SSL');
metrics.ssl = {};
ssl.split('\n').filter(l => l.includes('|')).forEach(line => {
  const [domain, expiry] = line.split('|');
  const d = domain.trim(); const e = expiry.trim();
  metrics.ssl[d] = e;
  if (!e || e === 'NONE') { addIssue('SSL', 'WARNING', d + ': no valid cert', 'certbot certificates'); }
  else { try {
    const daysLeft = Math.floor((new Date(e) - new Date()) / 86400000);
    if (daysLeft < 3) addIssue('SSL', 'CRITICAL', d + ' expires in ' + daysLeft + 'd', 'certbot renew');
    else if (daysLeft < 7) addIssue('SSL', 'WARNING', d + ' expires in ' + daysLeft + 'd', 'certbot renew');
  } catch(err) {} }
});

const summary = maxSeverity === 'HEALTHY'
  ? 'All OK: ' + cHealthy + '/' + containers.length + ' containers, RAM ' + (metrics.ram_available_mb || '?') + 'MB, Disk ' + (metrics.disk_root_percent || '?') + '%'
  : issues.map(i => '[' + i.component + '] ' + i.detail).join('; ');

return [{ json: { ssh_ok: true, severity: maxSeverity, summary, timestamp: metrics.check_time, issues, metrics } }];
